import{_ as s,o as n,c as e,S as l}from"./chunks/framework.C6RQlTYc.js";const h=JSON.parse('{"title":"面试官问：什么是 RLHF？大模型为什么要对齐？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_10-rlhf.md","filePath":"面试官问/17ai/q_ai_10-rlhf.md","lastUpdated":1778207238000}'),p={name:"面试官问/17ai/q_ai_10-rlhf.md"};function i(r,a,t,o,c,u){return n(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="面试官问-什么是-rlhf-大模型为什么要对齐" tabindex="-1">面试官问：什么是 RLHF？大模型为什么要对齐？ <a class="header-anchor" href="#面试官问-什么是-rlhf-大模型为什么要对齐" aria-label="Permalink to &quot;面试官问：什么是 RLHF？大模型为什么要对齐？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_15-rlhf.html">RLHF 与对齐训练</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_30-safety.html">AI 安全与护栏</a></p></blockquote><p><strong>场景</strong>：面试官问&quot;为什么 ChatGPT 不会教你做炸弹？背后的 RLHF 是怎么工作的？&quot;</p><p><strong>考察点</strong>：RLHF 三阶段流程、对齐目标 HHH</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p><strong>RLHF</strong>（Reinforcement Learning from Human Feedback）是通过人类偏好反馈来训练模型的方法，核心目的是<strong>让模型输出&quot;符合人类价值观&quot;</strong>。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>RLHF 三阶段训练：</span></span>
<span class="line"><span>┌──────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Step 1：SFT 监督微调                          │</span></span>
<span class="line"><span>│ → 用高质量人类对话数据训练模型基本的对话能力      │</span></span>
<span class="line"><span>├──────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ Step 2：训练奖励模型（Reward Model）           │</span></span>
<span class="line"><span>│ → 人工标注：同样的问题，A 回答比 B 好          │</span></span>
<span class="line"><span>│ → 训练模型预测人类偏好，输出分数                │</span></span>
<span class="line"><span>├──────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ Step 3：PPO 强化学习                          │</span></span>
<span class="line"><span>│ → 用奖励模型打分，引导模型生成高分回答           │</span></span>
<span class="line"><span>│ → 同时惩罚偏离原始模型太远的回答（KL 散度约束）  │</span></span>
<span class="line"><span>└──────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p><strong>为什么需要对齐</strong>：预训练模型只是&quot;预测下一个 token&quot;，天生不会拒绝危险请求。RLHF 让模型学会：</p><ul><li>✅ 拒绝回答&quot;如何制作炸弹&quot;</li><li>✅ 承认&quot;我不知道&quot;而不是乱编</li><li>✅ 输出符合社会伦理的内容</li></ul><p><strong>HHH 对齐原则</strong>：</p><ul><li>Helpful（有帮助）：准确回答问题</li><li>Honest（诚实）：不编造、不误导</li><li>Harmless（无害）：拒绝有害请求</li></ul><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>记住三阶段：SFT → 奖励模型 → PPO</li><li>用一句话解释 RLHF：&quot;让人来打分，模型照着高分的方向学&quot;</li><li>知道对齐的目标是 HHH</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_15-rlhf.html">RLHF 与对齐训练概念讲解</a></p></blockquote>`,6)])])}const d=s(p,[["render",i]]);export{h as __pageData,d as default};
